import LocalAuthentication
import SwiftUI

class BiometricAuthenticationManager: ObservableObject {
    @Published var isAuthenticated = false
    @Published var authenticationError: String?
    
    private let context = LAContext()
    private let userDefaultsKey = "userIsAuthenticated"
    
    var biometricType: BiometricType {
        var error: NSError?
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            return .none
        }
        
        switch context.biometryType {
        case .faceID:
            return .faceID
        case .touchID:
            return .touchID
        case .opticID:
            return .opticID
        default:
            return .none
        }
    }
    
    enum BiometricType {
        case faceID
        case touchID
        case opticID
        case none
        
        var displayName: String {
            switch self {
            case .faceID: return "Face ID"
            case .touchID: return "Touch ID"
            case .opticID: return "Optic ID"
            case .none: return "Biometric Authentication"
            }
        }
        
        var iconName: String {
            switch self {
            case .faceID: return "faceid"
            case .touchID: return "touchid"
            case .opticID: return "opticid"
            case .none: return "lock.shield"
            }
        }
    }
    
    init() {
        isAuthenticated = UserDefaults.standard.bool(forKey: userDefaultsKey)
    }
    
    func authenticateWithBiometrics(completion: @escaping (Bool, String?) -> Void) {
        let context = LAContext()
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            let message = error?.localizedDescription ?? "Biometric authentication is not available on this device."
            completion(false, message)
            return
        }
        
        let reason = "Authenticate to access your account"
        
        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason) { [weak self] success, authenticationError in
            DispatchQueue.main.async {
                if success {
                    self?.isAuthenticated = true
                    UserDefaults.standard.set(true, forKey: self?.userDefaultsKey ?? "userIsAuthenticated")
                    completion(true, nil)
                } else {
                    let errorMessage = self?.handleAuthenticationError(authenticationError as? LAError)
                    completion(false, errorMessage)
                }
            }
        }
    }
    
    func authenticateWithDevicePasscode(completion: @escaping (Bool, String?) -> Void) {
        let context = LAContext()
        let reason = "Authenticate with your device passcode"
        
        context.evaluatePolicy(.deviceOwnerAuthentication, localizedReason: reason) { [weak self] success, error in
            DispatchQueue.main.async {
                if success {
                    self?.isAuthenticated = true
                    UserDefaults.standard.set(true, forKey: self?.userDefaultsKey ?? "userIsAuthenticated")
                    completion(true, nil)
                } else {
                    let errorMessage = self?.handleAuthenticationError(error as? LAError)
                    completion(false, errorMessage)
                }
            }
        }
    }
    
    private func handleAuthenticationError(_ error: LAError?) -> String {
        guard let error = error else {
            return "An unknown error occurred."
        }
        
        switch error.code {
        case .authenticationFailed:
            return "Authentication failed. Please try again."
        case .userCancel:
            return "Authentication was cancelled."
        case .userFallback:
            return "User chose to enter password."
        case .biometryNotAvailable:
            return "Biometric authentication is not available."
        case .biometryNotEnrolled:
            return "No biometric credentials are enrolled."
        case .biometryLockout:
            return "Too many failed attempts. Please use your device passcode."
        case .appCancel:
            return "Authentication was cancelled by the app."
        case .invalidContext:
            return "Authentication context is invalid."
        case .notInteractive:
            return "Authentication failed because user interaction is not allowed."
        case .passcodeNotSet:
            return "Passcode is not set on the device."
        case .systemCancel:
            return "Authentication was cancelled by the system."
        default:
            return "Authentication failed: \(error.localizedDescription)"
        }
    }
    
    func logout() {
        isAuthenticated = false
        UserDefaults.standard.set(false, forKey: userDefaultsKey)
    }
    
    func isBiometricAvailable() -> Bool {
        var error: NSError?
        return context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
    }
}

