struct ContentView: View {
    @StateObject private var authManager = BiometricAuthenticationManager()
    
    var body: some View {
        Group {
            if authManager.isAuthenticated {
                HomeView(authManager: authManager)
            } else {
                LoginView()
                    .environmentObject(authManager)
            }
        }
        .onAppear {
            if authManager.isAuthenticated && authManager.isBiometricAvailable() {
                authManager.authenticateWithBiometrics { success, error in
                    if !success {
                        authManager.logout()
                    }
                }
            }
        }
    }
}

